        else if (incentiveRate >= incentiveRateStored) {
            incentive.incentiveRate = incentiveRate;
        }
        else {
            InvalidIncentiveRate.selector.revertWith();
        }
        emit IncentiveAdded(token, msg.sender, amount, incentive.incentiveRate);
    }

